70	    systemInstruction: opts.system,
71	    responseMimeType: "application/json",
72	    maxOutputTokens: opts.maxTokens ?? 8192,
73	    temperature: opts.temperature ?? 0.7,
74	  };
75	
76	  const { text, modelUsed } = await callWithChain(opts.user, cfg);
77	
78	  if (!text) throw new Error(`Gemini (${modelUsed}) returned empty response`);
79	  const cleaned = text.replace(/^```json\s*/i, "").replace(/\s*```$/, "").trim();
80	  try {
81	    return JSON.parse(cleaned) as T;
82	  } catch (e) {
83	    // Truncation recovery: if the response looks like a JSON array that was cut
84	    // off mid-stream, extract all fully-closed objects and parse those.
85	    if (cleaned.startsWith("[")) {
86	      const objects: unknown[] = [];
87	      // Match top-level {...} blocks (handles nesting up to ~5 levels)
88	      const re = /\{(?:[^{}]|\{(?:[^{}]|\{(?:[^{}]|\{(?:[^{}]|\{[^{}]*\})*\})*\})*\})*\}/g;
89	      let m: RegExpExecArray | null;
90	      while ((m = re.exec(cleaned)) !== null) {
91	        try { objects.push(JSON.parse(m[0])); } catch { /* skip malformed fragment */ }
92	      }
93	      if (objects.length > 0) {
94	        console.warn(`[llm] ${modelUsed} response was truncated — recovered ${objects.length} complete object(s)`);
95	        return objects as T;
96	      }
97	    }
98	    throw new Error(
99	      `Gemini (${modelUsed}) returned non-JSON:\n${text.slice(0, 500)}\n\nParse error: ${(e as Error).message}`
100	    );
101	  }
102	}
