1	import { generateJSON } from "../llm/client";
2	import type { BrandReportRow, DomainReportRow } from "../peec/types";
3	import type { Insight } from "./types";
4	
5	type Args = {
6	  brandName: string;
7	  brandReport: BrandReportRow[];
8	  domainReport: DomainReportRow[];
9	  range: { start_date: string; end_date: string };
10	};
11	
12	type ComputedFacts = {
13	  brand: string;
14	  date_range: { start_date: string; end_date: string };
15	  own: {
16	    visibility_pct: number;
17	    share_of_voice_pct: number;
18	    sentiment: number;
19	    position: number;
20	    mention_count: number;
21	  };
22	  ranks: {
23	    visibility_rank: string;
24	    share_of_voice_rank: string;
25	    sentiment_rank: string;
26	    position_rank: string;
27	  };
28	  category_leaders: {
29	    visibility_leader: { name: string; visibility_pct: number };
30	    share_of_voice_leader: { name: string; share_of_voice_pct: number };
31	    sentiment_leader: { name: string; sentiment: number };
32	    position_leader: { name: string; position: number };
33	  };
34	  pattern_flags: string[];
35	  top_3_source_domains: { domain: string; classification: string; retrieval_count: number }[];
36	};
37	
38	export async function buildInsight(args: Args): Promise<Insight> {
39	  const { brandName, brandReport, domainReport, range } = args;
40	
41	  const own = brandReport.find((r) => r.brand.name === brandName);
42	  if (!own) {
43	    return {
44	      headline: `${brandName} not found in brand report`,
45	      subhead: "Check that this brand is configured with is_own:true in Peec.",
46	      evidence: [],
47	    };
48	  }
49	
50	  const facts = computeFacts(brandName, brandReport, domainReport, range);
51	
52	  return generateJSON<Insight>({
53	    system: insightSystem(),
54	    user: JSON.stringify(facts, null, 2),
55	    temperature: 0.5,
56	  });
57	}
58	
59	function computeFacts(brand: string, report: BrandReportRow[], domains: DomainReportRow[], range: { start_date: string; end_date: string }): ComputedFacts {
60	  const own = report.find((r) => r.brand.name === brand)!;
61	  const total = report.length;
62	
63	  // Lower position number = better rank, so sort ascending for position
64	  const byVisibility = [...report].sort((a, b) => b.visibility - a.visibility);
65	  const bySoV = [...report].sort((a, b) => b.share_of_voice - a.share_of_voice);
66	  const bySentiment = [...report].sort((a, b) => b.sentiment - a.sentiment);
67	  const byPosition = [...report].sort((a, b) => a.position - b.position);
68	
69	  const rank = (sorted: BrandReportRow[]) => sorted.findIndex((r) => r.brand.name === brand) + 1;
70	  const rankStr = (r: number) => `${r} of ${total}${r === 1 ? " (best)" : r === total ? " (worst)" : ""}`;
71	
72	  const flags: string[] = [];
73	  if (rank(byPosition) === 1 && own.visibility < 0.30) flags.push("BEST_POSITION_LOW_VISIBILITY: brand wins on quality but loses on frequency — distribution problem, not reputation problem");
74	  if (rank(byVisibility) === 1 && rank(byPosition) > total / 2) flags.push("HIGH_VISIBILITY_BAD_POSITION: mentioned often but always far down — reputation/messaging problem");
75	  if (own.sentiment >= 75 && own.visibility < 0.20) flags.push("HIGH_SENTIMENT_LOW_VISIBILITY: AI loves the brand but rarely surfaces it — needs more cited sources");
76	  if (own.sentiment < 55) flags.push("LOW_SENTIMENT: AI consistently describes the brand negatively — investigate the cited sources driving this");
77	  if (rank(bySoV) === 1) flags.push("DOMINANT_SOV: leading the category in mention share");
78	  if (rank(byVisibility) > total / 2 && rank(byPosition) > total / 2) flags.push("INVISIBLE_AND_LOW_RANKED: both quality and frequency need work");
79	
80	  return {
81	    brand,
82	    date_range: range,
83	    own: {
84	      visibility_pct: Number((own.visibility * 100).toFixed(1)),
85	      share_of_voice_pct: Number((own.share_of_voice * 100).toFixed(1)),
86	      sentiment: own.sentiment,
87	      position: Number(own.position.toFixed(2)),
88	      mention_count: own.mention_count,
89	    },
90	    ranks: {
91	      visibility_rank: rankStr(rank(byVisibility)),
92	      share_of_voice_rank: rankStr(rank(bySoV)),
93	      sentiment_rank: rankStr(rank(bySentiment)),
94	      position_rank: rankStr(rank(byPosition)),
95	    },
96	    category_leaders: {
97	      visibility_leader: { name: byVisibility[0].brand.name, visibility_pct: Number((byVisibility[0].visibility * 100).toFixed(1)) },
98	      share_of_voice_leader: { name: bySoV[0].brand.name, share_of_voice_pct: Number((bySoV[0].share_of_voice * 100).toFixed(1)) },
99	      sentiment_leader: { name: bySentiment[0].brand.name, sentiment: bySentiment[0].sentiment },
100	      position_leader: { name: byPosition[0].brand.name, position: Number(byPosition[0].position.toFixed(2)) },
101	    },
102	    pattern_flags: flags,
103	    top_3_source_domains: [...domains]
104	      .sort((a, b) => b.retrieval_count - a.retrieval_count)
105	      .slice(0, 3)
106	      .map((d) => ({ domain: d.domain, classification: d.classification, retrieval_count: d.retrieval_count })),
107	  };
108	}
109	
110	function insightSystem(): string {
111	  return `You are an AI search analyst. You write the single sharpest insight that frames a brand's situation in AI search.
112	
113	The user input is a STRUCTURED FACT BUNDLE — pre-computed. Your job is to interpret it into one tight paragraph, not recompute or re-rank anything.
114	
115	Key facts to lean on:
116	- "ranks" tells you where the brand stands on each metric (rank 1 is always best, including for position).
117	- "pattern_flags" identifies any classic competitive shape that applies — use them to anchor the headline.
118	- "category_leaders" name the brands winning each dimension. Reference them by name when relevant.
119	- For position: rank 1 means best (listed first in answers); higher rank = worse.
