    metadata: {
      topic: "Counter-narrative",
      hashtags: [],
      platforms: ["YOUTUBE", "TIKTOK", "X"] as ("YOUTUBE" | "TIKTOK" | "INSTAGRAM" | "X")[],
    },
  }));

  // D. Low Sentiment Shorts
  const lowSentimentItems = (slate.low_sentiment_shorts || []).map((s) => ({
    type: "SHORT" as const,
    title: `Combat: ${s.topic}`,
