5	
6	if (!hasTavily) {
7	  console.error("\nTAVILY_API_KEY missing in .env — get one at https://tavily.com\n");
8	  process.exit(1);
9	}
10	
11	console.log(`\n${"━".repeat(72)}`);
12	console.log(`  Vairal × Tavily — fresh news layer for Shorts wedges`);
13	console.log(`${"━".repeat(72)}\n`);
14	
15	let slate: Slate;
16	try {
17	  slate = JSON.parse(await readFile("data/slate/latest.json", "utf8")) as Slate;
18	} catch {
19	  console.error("No slate found — run `npm run slate` first.\n");
20	  process.exit(1);
