23	console.log(`Brand: ${slate.brand.name}`);
24	console.log(`Slate generated: ${new Date(slate.generated_at).toLocaleString()}\n`);
25	
26	if (slate.shorts.length === 0) {
27	  console.log("Slate has no shorts to enrich.\n");
28	  process.exit(0);
29	}
