31	for (let i = 0; i < slate.shorts.length; i++) {
32	  const s = slate.shorts[i];
33	  const wedge = s.competitor_wedge;
34	  // Hot-take queries work best with just the competitor name + a simple negative anchor
35	  // — the "weak_topic" field is often localized or jargon-y, which pollutes news retrieval.
36	  const query = `${wedge.name} criticism review problems controversy`;
37	
38	  console.log(`${"─".repeat(72)}`);
39	  console.log(`  Short ${i + 1}/${slate.shorts.length}  ·  vs ${wedge.name}  (${wedge.weak_topic})`);
