1	"use client";
2	
3	import { useEffect, useState } from "react";
4	import { useRouter } from "next/navigation";
5	
6	type ProjectInfo = { id: string; name: string; status: string };
7	
8	export function BrandPicker({ currentBrand }: { currentBrand: string }) {
9	  const router = useRouter();
10	  const [projects, setProjects] = useState<ProjectInfo[] | null>(null);
11	  const [generating, setGenerating] = useState<string | null>(null);
12	  const [error, setError] = useState<string | null>(null);
13	
14	  const [progress, setProgress] = useState(0);
15	
16	  useEffect(() => {
17	    let cancelled = false;
18	    fetch("/api/projects")
19	      .then((r) => r.json())
20	      .then((data) => {
21	        if (cancelled) return;
22	        if (data.error) setError(data.error);
23	        else setProjects(data.projects ?? []);
24	      })
25	      .catch((e) => !cancelled && setError(e.message));
26	    return () => { cancelled = true; };
27	  }, []);
28	
29	  // Fake progress bar while generating
30	  useEffect(() => {
31	    if (!generating) {
32	      setProgress(0);
33	      return;
34	    }
35	    const interval = setInterval(() => {
36	      setProgress((p) => {
37	        if (p >= 100) return 100;
38	        const remaining = 95 - p;
39	        if (remaining <= 1) return 95;
40	        return p + remaining * 0.05;
41	      });
42	    }, 500);
43	    return () => clearInterval(interval);
44	  }, [generating]);
45	
46	  async function generate(projectId: string) {
47	    setGenerating(projectId);
48	    setProgress(0);
49	    setError(null);
50	    try {
51	      const res = await fetch("/api/generate", {
52	        method: "POST",
53	        headers: { "Content-Type": "application/json" },
54	        body: JSON.stringify({ project: projectId }),
55	      });
56	      const data = await res.json();
57	      if (!res.ok) throw new Error(data.error ?? "Generation failed");
58	      setProgress(100);
59	      // Wait a tiny bit so the user sees 100% before it refreshes
60	      setTimeout(() => {
61	        setGenerating(null);
62	        router.refresh();
63	      }, 500);
64	    } catch (e) {
65	      setError((e as Error).message);
66	      setGenerating(null);
67	      setProgress(0);
68	    }
69	  }
70	
71	  if (!projects) {
72	    return (
73	      <div className="mt-8 text-sm text-neutral-500 font-mono">Loading projects from Peec…</div>
74	    );
75	  }
76	
77	  if (projects.length === 0) {
78	    return (
79	      <div className="mt-8 text-sm text-neutral-500">
80	        No Peec projects accessible to this API key. Create one in the Peec dashboard.
81	      </div>
82	    );
83	  }
84	
85	  return (
86	    <div className="mt-8">
87	      <div className="flex items-center gap-3 mb-3">
88	        <span className="font-mono text-xs uppercase tracking-widest text-neutral-500">
89	          Generate slate for ({projects.length} projects available)
90	        </span>
91	        {error && <span className="text-sm text-red-600">⚠ {error}</span>}
92	      </div>
93	      <div className="mt-2">
94	        <select
95	          disabled={generating !== null}
96	          onChange={(e) => {
97	            if (e.target.value) generate(e.target.value);
98	          }}
