1	import { readFile } from "node:fs/promises";
2	import { join } from "node:path";
3	import type { Slate, SourceGap } from "@/lib/pipeline/types";
4	import { BrandPicker } from "./components/BrandPicker";
5	import { generateSmartPlan } from "@/lib/pipeline/planner";
6	import { ContentCard } from "./components/ContentDetailView";
7	import { PitchCard } from "./components/PitchCard";
8	import { GapCard } from "./components/GapCard";
9	import { EffectTab } from "./components/EffectTab";
10	
11	async function loadSlate(): Promise<Slate | null> {
12	  try {
13	    const raw = await readFile(join(process.cwd(), "data/slate/latest.json"), "utf8");
14	    return JSON.parse(raw) as Slate;
15	  } catch {
16	    return null;
17	  }
18	}
19	
20	export const dynamic = "force-dynamic";
21	
22	
23	function Header() {
24	  return (
25	    <header className="flex justify-between items-end">
26	      <div>
27	        <p className="font-mono text-xs uppercase tracking-widest text-accent">Vairal</p>
28	        <h1 className="mt-3 text-5xl font-semibold tracking-tight">Founder channel engine</h1>
29	        <p className="mt-3 text-lg text-neutral-600 max-w-2xl">
30	          Pick an underdog brand. Vairal reads how AI search is talking about it right now, then drafts the week of content that earns more of those mentions.
31	        </p>
32	      </div>
33	    </header>
34	  );
35	}
36	
37	export default async function Home() {
38	  const slate = await loadSlate();
39	
40	  let plan: any;
41	  let gaps: SourceGap[] = [];
42	  let maxGapScore = 0;
43	  let dailyPlans: { date: Date; items: any[] }[] = [];
44	
45	  if (slate) {
46	    plan = generateSmartPlan(slate);
47	    gaps = slate.gap_analysis?.gaps ?? [];
48	    maxGapScore = gaps.reduce((m, g) => Math.max(m, g.gap_score), 0);
49	
50	    dailyPlans = Array.from({ length: 7 }, (_, i) => {
51	      const date = new Date();
52	      date.setDate(date.getDate() + i);
53	      const dateStr = date.toDateString();
54	      return {
55	        date,
56	        items: plan!.items.filter((item: any) => new Date(item.scheduled_at).toDateString() === dateStr),
57	      };
58	    });
59	  }
60	
61	  return (
62	    <main className="min-h-screen px-8 py-16 max-w-7xl mx-auto">
63	      <Header />
64	      <BrandPicker currentBrand={slate?.brand.name ?? ""} />
65	
66	      {!slate ? (
